import{C as n,o as s,c as l,a5 as t,E as i}from"./chunks/framework.CW28V7p_.js";const p=JSON.parse('{"title":"⭐ Module 1 — Final quiz","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/final-quiz.md","filePath":"module-1/final-quiz.md","lastUpdated":1780937944000}'),r={name:"module-1/final-quiz.md"},h=Object.assign(r,{setup(d){const a={id:"m1-final",title:"⭐ Module 1 — Final quiz",intro:"15 питань що синтезують усі 5 секцій Module 1. Цільте на 80%+.",questions:[{type:"mcq",q:"Що з цього правильне про cluster? (обери всі)",options:["Cluster має унікальний genesis hash","Один agave-validator binary може joinнути будь-який cluster (mainnet/testnet/devnet/Alpenglow)","SOL у mainnet можна перевести у testnet через bridge","Усі nodes у cluster мають однаковий software version"],correct:[0,1],explanation:"#1 правильно: genesis hash — unique fingerprint. #2 правильно: один binary, різний config. #3 НЕПРАВИЛЬНО: clusters separate, SOL не fungible. #4 НЕПРАВИЛЬНО: один cluster може мати nodes на різних patch versions (compatible)."},{type:"command",q:"Як переключити solana CLI на mainnet-beta?",accepts:["solana config set --url mainnet-beta","solana config set --url https://api.mainnet-beta.solana.com","solana config set -u mainnet-beta"],ideal:"solana config set --url mainnet-beta",explanation:"solana config set --url <network>. Shortcut: mainnet-beta, testnet, devnet, localhost. Module 1.1."},{type:"compare",q:"У чому різниця між slot і block?",ideal:`Slot це 400ms time window (continuous, незалежно від подій). Block це data container що може опціонально existувати у slot. Якщо leader зміг створити block у своєму slot — slot has block. Якщо не зміг — slot skipped (empty).

Ключові розбіжності:
1. Slot завжди existує (counter monotonically increases). Block conditional.
2. Slot timing fixed (400ms). Block size variable (залежить від TX).
3. Один slot = 0 або 1 blocks. Ніколи 2+.
4. Block height counts тільки produced blocks, slot number counts всі.`,explanation:"Ключове: slot = time window, block = data container. Slot може бути empty. Module 1.2."},{type:"mcq",q:"Скільки часу триває epoch на mainnet (приблизно)?",options:["~48 годин (~2 дні)","~24 години (1 день)","~1 година","~1 тиждень"],correct:[0],explanation:"432,000 slots × 400ms = 172,800 секунд = 48 годин. У реальності може бути 49-52 години через slight slot timing drift. Module 1.2."},{type:"command",q:"Як подивитись прогрес поточного epoch (% completed, скільки часу залишилось)?",accepts:["solana epoch-info","solana epoch-info --url mainnet-beta","sudo /home/solana/ag/bin/solana epoch-info --url http://localhost:8899"],ideal:"solana epoch-info",explanation:"solana epoch-info виводить slot range, completed percent, completed time. Module 1.2."},{type:"mcq",q:"Що з цього правильне про leader schedule? (обери всі правильні)",options:["Schedule визначається deterministically на base stake snapshot з кінця попереднього epoch","Schedule для всього epoch публікується заздалегідь (всі 432000 entries)","Validator з більшим stake отримує більше slots у schedule (proportional)","Якщо leader впав під час slot, інший validator перебирає live"],correct:[0,1,2],explanation:'Schedule deterministic, public, stake-proportional. Slots не "перебираються" — якщо leader fail, slot stays empty (skipped). Module 1.3.'},{type:"order",q:"Постав у правильному порядку steps що leader робить у своєму 400ms slot:",items:["Broadcast shreds через turbine","Open bank","Process transactions з TPU","Generate PoH ticks","Vote за parent block","Close bank"],correctOrder:[1,3,2,4,0,5],explanation:"Open bank → PoH start → process TXs → vote за parent → broadcast shreds (паралельно) → close bank. Module 1.4."},{type:"scenario",q:"Mainnet validator має skip rate 15% (norм 5%). Опиши 4 angles які варто investigate (technical, не organizational).",ideal:`1. CPU bottleneck: validator processing не встигає за 400ms. Run htop, дивись чи high CPU/IOwait. Solution: faster CPU (AMD EPYC, Intel Xeon Gold з high boost).

2. Disk I/O: повільний NVMe. iostat -x 1 покаже high await. Solution: enterprise NVMe (Samsung 980 Pro або better).

3. Network: high latency to peers або packet loss. ping/iperf до peers. Solution: better ISP/peering, possibly move datacenter.

4. RAM: under 256GB для mainnet → OS swapping. free -h check. Solution: upgrade RAM.

5. Software: regression у new agave version. Check release notes якщо щойно updateувала. Solution: downgrade per §4 Phase 6.

6. Logs analysis: sudo journalctl -u solana --since "1 hour ago" | grep -iE "error|warn" — конкретні errors під час leader slots.`,explanation:"Multi-angle thinking: hardware (CPU/disk/RAM), network, software, logs. Якщо описала 4+ angles — повна відповідь. Module 1.4."},{type:"diagnose",q:'Solana validators виводить тебе у "Delinquent Stake" sекції. Що правда (обери всі)?',options:["Validator не голосував > 128 slots на rooted slot","Validator продовжує заробляти rewards поки delinquent","Cluster автоматично slashes delinquent validators","Status може recoverитись коли validator catch up і resume voting"],correct:[0,3],explanation:"#1 правильно — це Solana definition. #4 правильно — recoverable. #2 НЕПРАВИЛЬНО — нема rewards поки delinquent. #3 НЕПРАВИЛЬНО — Solana НЕ slashing для delinquency (на цей момент). Module 1.5."},{type:"mcq",q:"Якщо cluster active stake падає нижче 67% — що відбувається?",options:["Cluster halts (не може finalize blocks)","Cluster slowly degrades (slots take longer)","Validators get auto-slashed","Епоха автоматично extendsся"],correct:[0],explanation:"Solana потребує > 2/3 stake voting для finality. Якщо delinquent > 33% (active < 67%) — cluster halts. Module 1.5."},{type:"command",q:"Як перевірити скільки vote credits ти заробила у останніх 3 epochs?",accepts:['solana vote-account YOUR_VOTE | grep -A 5 "Epoch Voting"',"solana vote-account YOUR_VOTE | grep -A 3 Credits",'sudo /home/solana/ag/bin/solana vote-account YOUR_VOTE --url http://localhost:8899 | grep -A 5 "Epoch Voting"'],ideal:'solana vote-account YOUR_VOTE | grep -A 5 "Epoch Voting"',explanation:"vote-account command виводить voting history з credits per epoch. grep -A N виводить N рядків після match. Module 1.5."},{type:"explain",q:"Поясни (своїми словами) як stake delegation activation працює через epoch boundaries.",ideal:`Стейк не активується миттю. Process:

1. Ти запускаєш delegate-stake на slot X (середина epoch N)
2. Stake переходить у status "activating" (= warmup) до кінця epoch N
3. На boundary epoch N → N+1 cluster робить snapshot всіх stakes — твій stake потрапляє у новий active stake set
4. На slot 0 epoch N+1 твій stake "active" — validator починає включати твою вагу у voting/leader schedule
5. У кінці epoch N+1 ти отримуєш свою частку rewards proportionally

Чому boundary гранична: consensus працює з одним stake snapshot per epoch (з міркувань determinism). Mid-epoch changes ламали б leader schedule і vote tallying. Тому всі stake operations effects відкладені до next boundary.

Same logic for deactivation: ти undelegate-stake — stake "deactivating" до кінця epoch — inactive у наступному.`,explanation:"Ключове: boundary-aligned activation, snapshot-based consensus. Якщо описала activating → boundary → active sequence — повна відповідь. Module 1.2."},{type:"mcq",q:"Що з цього є валідними причинами skipped slot? (обери всі)",options:["Hardware повільний — не встиг compile block за 400ms","Network лагав, shreds не доcтачились до cluster","Інший validator забрав slot (race)","Validators software crashed mid-slot"],correct:[0,1,3],explanation:"Hardware, network, software crash — real causes. Race не може бути — slot fixed для одного leader, no override. Module 1.4."},{type:"compare",q:"У чому різниця між Processed, Confirmed, і Finalized slot?",ideal:`Processed: останній slot який твій validator обробив локально (включено TX у local bank). Найвищий number.

Confirmed: slot який ≥ 2/3 stake проголосувала за. Lower number (старіший) ніж Processed.

Finalized: slot який має full finality (31+ vote credits, irreversible). Найнижчий (найстаріший) з трьох.

Ordering: Processed > Confirmed > Finalized.

Difference indicates consensus latency. На mainnet типово Processed-Finalized = 12-32 slots (~5-12 секунд).

Для validator ops: коли ти у monitor бачиш ці три — Processed = "я бачу", Finalized = "ми всі точно згодні". Якщо різниця велика — cluster має consensus issues.`,explanation:"Ordering matters. Якщо описала ordering + meaning — повна відповідь. Module 1.2."},{type:"command",q:"Як подивитись скільки validators активних на mainnet прямо зараз?",accepts:['solana validators --url mainnet-beta | grep -c "^✓"','solana validators --url mainnet-beta | grep "^✓" | wc -l','solana validators --url mainnet-beta --output json | jq "[.validators[] | select(.delinquent == false)] | length"'],ideal:'solana validators --url mainnet-beta | grep -c "^✓"',explanation:"Validator row starts з ✓ (voting) або ⚠ (delinquent). grep -c counts matches. На mainnet типово ~1500-2000. Module 1.5."},{type:"explain",q:"Чим відрізняється in-genesis від out-of-genesis joining нового cluster?",ideal:`In-genesis: operator fills form до launch, його validator pubkey включений у initial genesis з initial stake. Starts validator у coordinated launch time з cluster. Гарантоване місце у first epoch leader schedule.

Out-of-genesis (LumLabs Alpenglow case 2026-06): missed initial form. Cluster launches без вас. Later join: wipe ledger, download cluster genesis, sync, create vote account, self-stake, wait for organizer to delegate community stake.

Difference: in-genesis ready from slot 0. Out-of-genesis joins mid-flight, needs catch-up + manual setup. Both valid paths. Module 1.6.`,explanation:""}]};return(c,e)=>{const o=n("Quiz");return s(),l("div",null,[e[0]||(e[0]=t("",5)),i(o,{data:a}),e[1]||(e[1]=t("",6))])}}});export{p as __pageData,h as default};
